export type Stream = 'Polytechnic' | 'B.Tech';

export type Branch = 'CSE' | 'Civil' | 'Mechanical' | 'EEE' | 'ECE' | 'IT';

export type ResourceType = 'Syllabus' | 'Notes' | 'PYQ';

export interface AcademicResource {
  id: string;
  title: string;
  description: string;
  stream: Stream;
  semester: number;
  branch: Branch;
  type: ResourceType;
  fileUrl: string;
}

export interface Internship {
  id: string;
  title: string;
  company: string;
  location: string;
  type: 'Online' | 'Offline';
  duration: string;
  fee: string;
  applicationUrl: string;
  status: 'Pending' | 'Approved' | 'Rejected';
  postedAt: string;
}

export interface Notice {
  id: string;
  title: string;
  content: string;
  date: string;
  isImportant: boolean;
}

import { GoogleGenAI } from "@google/genai";

export const getGeminiHelp = async (query: string) => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are an academic assistant for engineering students in Bihar. 
      The student asks: "${query}". 
      Provide a brief, helpful answer focused on Bihar technical education (BEU, SBTE Bihar).`,
    });
    return response.text;
  } catch (error) {
    console.error("Gemini assistance error:", error);
    return "Sorry, I couldn't process your request at the moment. Please try again later.";
  }
};

